from config import create_config


class ConfigMiddleware:
    """Middleware that loads config once and applies per-request overrides."""

    def __init__(self):
        # Cache a base config snapshot created from defaults at init time.
        self._base = create_config()  # cached at init time (create_config returns a copy)

    def apply_config(self, request_overrides=None):
        """Return config for this request, applying any overrides."""
        # Work on a copy of the cached base so per-request overrides don't mutate it.
        cfg = dict(self._base)  # work on a copy to avoid mutating cached base
        if request_overrides:
            cfg.update(request_overrides)
        return cfg

    def get_timeout(self):
        return self._base.get("timeout", 30)
