"""Message sender with retry and store integration."""

from store import append, notify, get_messages, get_notifications, reset as store_reset

_attempt_count = 0


def reset():
    global _attempt_count
    _attempt_count = 0
    # delegate store reset to the store module
    store_reset()


def send(msg, fail_first=False):
    """Send a message: store it and notify.

    If fail_first is True, raises on first call to simulate transient error.
    """
    global _attempt_count
    _attempt_count += 1
    if fail_first and _attempt_count == 1:
        raise ConnectionError("transient failure")
    append(msg)
    notify(msg)
    return True


def send_with_retry(msg, max_retries=2, fail_first=False):
    """Retry send on transient errors.

    Attempts up to max_retries times. Returns True on success. Raises
    the last ConnectionError if all attempts fail.
    """
    last_error = None
    for attempt in range(max_retries):
        try:
            send(msg, fail_first=fail_first)
            # success — return immediately to avoid duplicate sends
            return True
        except ConnectionError as e:
            last_error = e
            # continue to next attempt
            continue
    # all attempts exhausted
    if last_error:
        raise last_error
    return False


def get_attempt_count():
    return _attempt_count


