    """Retry send on transient errors. Returns True on success, False on failure."""
    # Attempt up to max_retries times
    for attempt in range(1, max_retries + 1):
        try:
            send(msg, fail_first=fail_first)
            return True
        except ConnectionError:
            # If this was the last allowed attempt, report failure
            if attempt == max_retries:
                return False
            # otherwise continue and retry
            continue
    return False


