    global _ingest_log
    _ingest_log = []
    # Use module reset functions instead of reaching into other modules' internals
    reset_store()
    reset_sender()


def ingest(msg, max_pipeline_retries=2, fail_first=False):
    """Ingest a message with pipeline-level retry."""
    for attempt in range(max_pipeline_retries):
        try:
            success = send_with_retry(msg, max_retries=2, fail_first=fail_first)
            if success:
                break
        except Exception:
            # Catch unexpected exceptions at pipeline level and retry
            continue
    # Log the ingestion once (after success or final attempt)
    _ingest_log.append(msg)
    return True


