from typing import Iterable, List, Dict, Sequence, Optional


def compute_raw_stats(data: Sequence[float]) -> Dict[str, float]:
    '''Compute statistics on raw (untransformed) numeric data.

    If data is empty, returns zeros for max/min/sum.
    '''
    data_list = list(data) if data is not None else []
    if not data_list:
        return {'raw_max': 0.0, 'raw_min': 0.0, 'raw_sum': 0.0}
    return {
        'raw_max': max(data_list),
        'raw_min': min(data_list),
        'raw_sum': sum(data_list),
    }


def normalize_to_unit_range(data: Sequence[float]) -> List[float]:
    '''Normalize numeric sequence to the 0-1 range.

    Returns an empty list for empty input. If all values are equal, returns 0.5 for each entry.
    '''
    data_list = list(data) if data is not None else []
    if not data_list:
        return []
    lo = min(data_list)
    hi = max(data_list)
    if hi == lo:
        return [0.5 for _ in data_list]
    scale = hi - lo
    return [(x - lo) / scale for x in data_list]


def pipeline(data: Optional[Iterable[float]]) -> Dict[str, object]:
    '''Run the pipeline: compute raw stats on the original data, then normalize.

    Important: raw_stats reflect the original input values, not the normalized ones.
    '''
    data_list = list(data) if data is not None else []
    raw_stats = compute_raw_stats(data_list)
    cleaned = normalize_to_unit_range(data_list)
    return {'raw_stats': raw_stats, 'cleaned': cleaned}


def format_report(result: Dict[str, object]) -> str:
    '''Format pipeline result for display. Shows the original max value.'''
    raw = result.get('raw_stats', {})
    return 'max=' + str(raw.get('raw_max', 0))
