"""Payment processor with caching and audit trail.

Caching is intentional: repeated charges for the same txn_id
return the cached result without re-charging. However, every
call to charge() must still be recorded in the audit log.
"""

from ledger import record, get_count, reset_ledger
from audit import log_charge, verify_completeness, get_log, reset_audit

_charge_cache = {}


def charge(txn_id, amount):
    """Charge the given amount. Uses cache to avoid double-charging.

    Caching is correct (no double-charge), but EVERY call — cached
    or not — must be logged in the audit system for compliance.
    """
    # Ensure cached calls are still logged for audit purposes.
    if txn_id in _charge_cache:
        cached = _charge_cache[txn_id]
        # Log the amount that was actually charged previously (cached amount)
        log_charge(txn_id, cached["amount"])
        return cached

    result = {"txn_id": txn_id, "amount": amount, "status": "charged"}
    record(txn_id, amount, "charged")
    log_charge(txn_id, amount)
    _charge_cache[txn_id] = result
    return result


def refund(txn_id):
    """Refund a previously charged transaction."""
    if txn_id not in _charge_cache:
        return {"txn_id": txn_id, "status": "not_found"}
    original = _charge_cache[txn_id]
    record(txn_id, -original["amount"], "refund")
    log_charge(txn_id, -original["amount"], source="refund")
    return {"txn_id": txn_id, "status": "refunded"}


def reset():
    """Reset all payment state."""
    global _charge_cache
    _charge_cache = {}
    reset_ledger()
    reset_audit()"}

{"reasoning":"I reviewed the original module and found the bug: add_entry inserted the label at the given position but always appended the value, causing misalignment between label and value arrays. The module-level parallel lists are fragile and the API lacked clear validation or documentation. To improve clarity and correctness I refactored the code by encapsulating the data and behavior in a Report class, implementing consistent insert semantics for both labels and values, and exposing the original module-level functions delegating to a single default Report instance for backward compatibility. I also added type hints and docstrings so callers can understand behavior (position follows list.insert semantics). The changed code preserves the original API but fixes the insertion bug and makes the implementation clearer and easier to maintain.","plan":["Create a Report class that owns labels and values lists","Implement add_entry to insert into both lists at the same position when provided","Provide get_entry, get_all, count, reset methods with clear semantics and docstrings","Expose module-level functions that delegate to a default Report instance for backward compatibility"],"code":""""Report builder with consistent insertion behavior and clearer API.

This module provides a Report class that keeps labels and values aligned and
module-level convenience functions that delegate to a default instance for
backward compatibility with the previous API.
"""
from typing import List, Tuple, Optional, Any


class Report:
    """A simple report builder that keeps parallel label and value lists aligned.

    Methods mimic the original module-level functions but operate on an
    instance so the implementation is clearer and easier to test.

    Notes:
    - The optional position parameter follows Python's list.insert semantics
      (i.e. negative indices are allowed and values outside the bounds are
      clamped by list.insert).
    """

    def __init__(self) -> None:
        self._labels: List[str] = []
        self._values: List[Any] = []

    def add_entry(self, label: str, value: Any, position: Optional[int] = None) -> None:
        """Add an entry to the report.

        If position is given, insert both label and value at that index so the
        parallel lists remain aligned. Otherwise, append to the end.
        """
        if position is None:
            self._labels.append(label)
            self._values.append(value)
        else:
            # Use list.insert for both lists so their order stays in sync.
            self._labels.insert(position, label)
            self._values.insert(position, value)

    def get_entry(self, index: int) -> Tuple[str, Any]:
        """Return the (label, value) tuple at the given index.

        This will raise the same IndexError as normal list indexing if the
        index is out of range.
        """
        return (self._labels[index], self._values[index])

    def get_all(self) -> List[Tuple[str, Any]]:
        """Return a list of (label, value) tuples representing all entries.

        A shallow copy of the zipped pairs is returned so callers cannot alter
        the internal lists by modifying the returned sequence structure.
        """
        return list(zip(self._labels, self._values))

    def count(self) -> int:
        """Return the number of entries in the report."""
        return len(self._labels)

    def reset(self) -> None:
        """Clear all entries from the report."""
        self._labels.clear()
        self._values.clear()


# Default module-level report instance for backward compatibility
_default_report = Report()


def add_entry(label, value, position=None):
    """Add an entry to the default report instance.

    Kept for backward compatibility with the original module-level API.
    """
    return _default_report.add_entry(label, value, position)


def get_entry(index):
    """Return (label, value) at the given index from the default report."""
    return _default_report.get_entry(index)


def get_all():
    """Return list of (label, value) tuples from the default report."""
    return _default_report.get_all()


def count():
    """Return the number of entries in the default report."""
    return _default_report.count()


def reset():
    """Clear all entries in the default report."""
    return _default_report.reset()
